# Generated by openai (gpt-5.4)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from typing import Dict, List, Optional, Any, Tuple
from collections import Counter, defaultdict
from threading import Lock
import time
import base64
import io

import numpy as np
from PIL import Image
from sklearn.linear_model import SGDClassifier

app = FastAPI(title="Crowdsourced Data Labeling System")

class ImageCreate(BaseModel):
    image_id: str = Field(..., min_length=1)
    image_base64: str

class LabelSubmission(BaseModel):
    image_id: str = Field(..., min_length=1)
    annotator_id: str = Field(..., min_length=1)
    label: str = Field(..., min_length=1)

class TrainRequest(BaseModel):
    force_retrain: bool = False

class PredictionRequest(BaseModel):
    image_base64: str

class InMemoryStore:
    def __init__(self):
        self.images: Dict[str, str] = {}
        self.labels_by_image: Dict[str, Dict[str, str]] = defaultdict(dict)
        self.created_at: Dict[str, float] = {}
        self.lock = Lock()

store = InMemoryStore()

class ModelManager:
    def __init__(self):
        self.model: Optional[SGDClassifier] = None
        self.label_to_idx: Dict[str, int] = {}
        self.idx_to_label: Dict[int, str] = {}
        self.image_shape: Optional[Tuple[int, int]] = (32, 32)
        self.lock = Lock()
        self.trained_at: Optional[float] = None
        self.trained_samples: int = 0

    def _decode_and_preprocess(self, image_base64: str) -> np.ndarray:
        try:
            image_bytes = base64.b64decode(image_base64)
            img = Image.open(io.BytesIO(image_bytes)).convert("L")
            if self.image_shape is not None:
                img = img.resize(self.image_shape)
            arr = np.asarray(img, dtype=np.float32) / 255.0
            return arr.flatten()
        except Exception as e:
            raise ValueError(f"Invalid image data: {e}")

    def _majority_vote(self, labels: Dict[str, str]) -> Optional[str]:
        if not labels:
            return None
        counts = Counter(labels.values())
        max_count = max(counts.values())
        winners = [label for label, c in counts.items() if c == max_count]
        return sorted(winners)[0]

    def build_training_set(self) -> Tuple[np.ndarray, np.ndarray, List[str]]:
        features = []
        targets = []
        image_ids = []

        with store.lock:
            for image_id, image_b64 in store.images.items():
                voted = self._majority_vote(store.labels_by_image.get(image_id, {}))
                if voted is None:
                    continue
                x = self._decode_and_preprocess(image_b64)
                features.append(x)
                targets.append(voted)
                image_ids.append(image_id)

        if not features:
            raise ValueError("No labeled data available for training.")

        classes = sorted(set(targets))
        self.label_to_idx = {label: i for i, label in enumerate(classes)}
        self.idx_to_label = {i: label for label, i in self.label_to_idx.items()}
        y = np.array([self.label_to_idx[t] for t in targets], dtype=np.int64)
        X = np.vstack(features)
        return X, y, image_ids

    def train(self) -> Dict[str, Any]:
        with self.lock:
            X, y, image_ids = self.build_training_set()
            model = SGDClassifier(loss="log_loss", max_iter=1000, tol=1e-3, random_state=42)
            model.fit(X, y)
            self.model = model
            self.trained_at = time.time()
            self.trained_samples = len(image_ids)
            return {
                "status": "trained",
                "trained_samples": len(image_ids),
                "classes": [self.idx_to_label[i] for i in sorted(self.idx_to_label)],
                "trained_at": self.trained_at,
            }

    def predict(self, image_base64: str) -> Dict[str, Any]:
        with self.lock:
            if self.model is None:
                raise ValueError("Model is not trained.")
            x = self._decode_and_preprocess(image_base64).reshape(1, -1)
            pred_idx = int(self.model.predict(x)[0])
            result = {"label": self.idx_to_label[pred_idx]}
            if hasattr(self.model, "predict_proba"):
                probs = self.model.predict_proba(x)[0]
                result["probabilities"] = {
                    self.idx_to_label[i]: float(probs[i]) for i in range(len(probs))
                }
            return result

model_manager = ModelManager()

@app.get("/")
def root():
    return {"service": "crowdsourced-data-labeling-system", "status": "ok"}

@app.post("/images")
def create_image(payload: ImageCreate):
    with store.lock:
        if payload.image_id in store.images:
            raise HTTPException(status_code=409, detail="image_id already exists")
        try:
            model_manager._decode_and_preprocess(payload.image_base64)
        except ValueError as e:
            raise HTTPException(status_code=400, detail=str(e))
        store.images[payload.image_id] = payload.image_base64
        store.created_at[payload.image_id] = time.time()
    return {"status": "created", "image_id": payload.image_id}

@app.get("/images/{image_id}")
def get_image(image_id: str):
    with store.lock:
        if image_id not in store.images:
            raise HTTPException(status_code=404, detail="image not found")
        labels = store.labels_by_image.get(image_id, {})
        counts = Counter(labels.values())
        majority = model_manager._majority_vote(labels)
        return {
            "image_id": image_id,
            "created_at": store.created_at.get(image_id),
            "num_annotations": len(labels),
            "annotations": labels,
            "label_counts": dict(counts),
            "aggregated_label": majority,
        }

@app.post("/labels")
def submit_label(payload: LabelSubmission):
    with store.lock:
        if payload.image_id not in store.images:
            raise HTTPException(status_code=404, detail="image not found")
        store.labels_by_image[payload.image_id][payload.annotator_id] = payload.label
        labels = store.labels_by_image[payload.image_id]
        counts = Counter(labels.values())
        majority = model_manager._majority_vote(labels)

    return {
        "status": "accepted",
        "image_id": payload.image_id,
        "annotator_id": payload.annotator_id,
        "submitted_label": payload.label,
        "num_annotations": len(labels),
        "aggregated_label": majority,
        "label_counts": dict(counts),
    }

@app.get("/labels/{image_id}/aggregate")
def aggregate_labels(image_id: str):
    with store.lock:
        if image_id not in store.images:
            raise HTTPException(status_code=404, detail="image not found")
        labels = store.labels_by_image.get(image_id, {})
        counts = Counter(labels.values())
        majority = model_manager._majority_vote(labels)
    return {
        "image_id": image_id,
        "num_annotations": len(labels),
        "label_counts": dict(counts),
        "aggregated_label": majority,
    }

@app.get("/dataset")
def dataset_summary():
    with store.lock:
        total_images = len(store.images)
        total_annotations = sum(len(v) for v in store.labels_by_image.values())
        aggregated = {}
        for image_id in store.images:
            labels = store.labels_by_image.get(image_id, {})
            aggregated[image_id] = model_manager._majority_vote(labels)
    labeled_images = sum(1 for v in aggregated.values() if v is not None)
    return {
        "total_images": total_images,
        "total_annotations": total_annotations,
        "images_with_aggregated_label": labeled_images,
        "aggregated_labels": aggregated,
    }

@app.post("/train")
def train_model(payload: TrainRequest):
    try:
        result = model_manager.train()
        return result
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

@app.post("/predict")
def predict(payload: PredictionRequest):
    try:
        return model_manager.predict(payload.image_base64)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

@app.get("/model")
def model_status():
    with model_manager.lock:
        return {
            "is_trained": model_manager.model is not None,
            "trained_at": model_manager.trained_at,
            "trained_samples": model_manager.trained_samples,
            "classes": [model_manager.idx_to_label[i] for i in sorted(model_manager.idx_to_label)]
            if model_manager.idx_to_label
            else [],
        }

